"""
patch_anim_cubes.py
Replaces the text-only getAnimSVG() in the Cubes explain page
with rich SVG visual animations.
"""
import re, os

PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)),
                    'explain', 'class8', 'arithmetic', 'cubes-and-cube-roots.html')

NEW_ANIM = r"""function getAnimSVG(t){
  var B=svgBase;
  function pill(x,y,w,txt,bg,tc){return '<rect x="'+x+'" y="'+(y-14)+'" width="'+w+'" height="22" rx="8" fill="'+bg+'"/><text x="'+(x+w/2)+'" y="'+y+'" text-anchor="middle" font-family="Share Tech Mono" font-size="13" font-weight="bold" fill="'+(tc||'#fff')+'">'+txt+'</text>';}
  function triBox(x,y,a,b,c,ok){var col=ok?'#7a8c6e':'#b85c2a';return '<rect x="'+x+'" y="'+y+'" width="28" height="22" rx="4" fill="'+col+'"/><text x="'+(x+14)+'" y="'+(y+15)+'" text-anchor="middle" font-family="Share Tech Mono" font-size="11" font-weight="bold" fill="#fff">'+a+'</text><rect x="'+(x+32)+'" y="'+y+'" width="28" height="22" rx="4" fill="'+col+'"/><text x="'+(x+46)+'" y="'+(y+15)+'" text-anchor="middle" font-family="Share Tech Mono" font-size="11" font-weight="bold" fill="#fff">'+b+'</text><rect x="'+(x+64)+'" y="'+y+'" width="28" height="22" rx="4" fill="'+col+'"/><text x="'+(x+78)+'" y="'+(y+15)+'" text-anchor="middle" font-family="Share Tech Mono" font-size="11" font-weight="bold" fill="#fff">'+c+'</text>';}
  var m={
  "cb1":function(){
    function cube3d(x,y,sz){var d=sz/2;return '<polygon points="'+x+','+(y+d)+' '+(x+sz)+','+y+' '+(x+2*sz)+','+(y+d)+' '+(x+sz)+','+(y+2*d)+'" fill="#e8c97a"/>'+'<polygon points="'+x+','+(y+d)+' '+x+','+(y+d+sz)+' '+(x+sz)+','+(y+2*d+sz)+' '+(x+sz)+','+(y+2*d)+'" fill="#a0522d"/>'+'<polygon points="'+(x+sz)+','+(y+2*d)+' '+(x+sz)+','+(y+2*d+sz)+' '+(x+2*sz)+','+(y+d+sz)+' '+(x+2*sz)+','+(y+d)+'" fill="#d4870a"/>'+'';}
    return B()+'<g id="cb1s0" opacity="0">'+'<text x="200" y="14" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="800" fill="#5a4a30">A perfect cube fills a 3-D cube exactly</text>'+cube3d(14,18,28)+'<text x="56" y="90" text-anchor="middle" font-family="Share Tech Mono" font-size="10" fill="#d4870a">1x1x1=1</text>'+cube3d(88,12,38)+'<text x="152" y="90" text-anchor="middle" font-family="Share Tech Mono" font-size="10" fill="#7a8c6e">2x2x2=8</text>'+cube3d(180,6,48)+'<text x="276" y="90" text-anchor="middle" font-family="Share Tech Mono" font-size="10" fill="#c8922a">3x3x3=27</text>'+'</g>'+'<g id="cb1s1" opacity="0"><text x="200" y="110" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">Perfect cubes: 1, 8, 27, 64, 125, 216, 343...</text></g>'+'<g id="cb1s2" opacity="0"><text x="200" y="134" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#7a8c6e">Is 216 a perfect cube? 6x6x6 = 216 YES!</text></g>'+'<g id="cb1ans" opacity="0">'+svgAns("6^3 = 216")+'</g></svg>';},
  "cb2":function(){return B()+'<g id="cb2s0" opacity="0"><text x="200" y="16" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">512 = 2^9 -- group prime factors in triples</text>'+triBox(20,28,'2','2','2',true)+triBox(110,28,'2','2','2',true)+triBox(200,28,'2','2','2',true)+'</g>'+'<g id="cb2s1" opacity="0"><text x="200" y="72" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#7a8c6e">Three complete triples -- all in groups of 3</text>'+pill(20,90,90,'one 2','#d4870a')+pill(120,90,90,'one 2','#d4870a')+pill(220,90,90,'one 2','#d4870a')+'</g>'+'<g id="cb2s2" opacity="0"><text x="200" y="118" text-anchor="middle" font-family="Nunito" font-size="14" font-weight="900" fill="#c8922a">cbrt(512) = 2x2x2 = 8 OK</text></g>'+'<g id="cb2ans" opacity="0">'+svgAns("cbrt(512) = 8")+'</g></svg>';},
  "cb3":function(){return B()+'<g id="cb3s0" opacity="0"><text x="200" y="16" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">Negative x Negative x Negative = Negative</text>'+pill(30,44,150,'(-5) x (-5) = +25','#7a8c6e')+pill(220,44,150,'(+25) x (-5) = -125','#b85c2a')+'</g>'+'<g id="cb3s1" opacity="0"><text x="200" y="78" text-anchor="middle" font-family="Nunito" font-size="14" font-weight="900" fill="#c8922a">(-5)^3 = -125</text><text x="200" y="100" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">So cbrt(-125) = -5</text></g>'+'<g id="cb3s2" opacity="0"><text x="200" y="126" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#7a8c6e">Rule: cbrt(-n) = -(cbrt(n)) always</text></g>'+'<g id="cb3ans" opacity="0">'+svgAns("cbrt(-125) = -5")+'</g></svg>';},
  "cb4":function(){return B()+'<g id="cb4s0" opacity="0"><text x="200" y="16" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">1000 -- group prime factors in triples</text>'+triBox(30,28,'2','2','2',true)+triBox(140,28,'5','5','5',true)+'</g>'+'<g id="cb4s1" opacity="0"><text x="200" y="74" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#7a8c6e">Two perfect triples: (2x2x2) and (5x5x5)</text></g>'+'<g id="cb4s2" opacity="0"><text x="200" y="100" text-anchor="middle" font-family="Nunito" font-size="14" font-weight="900" fill="#c8922a">cbrt(1000) = 2x5 = 10  YES!</text></g>'+'<g id="cb4ans" opacity="0">'+svgAns("cbrt(1000) = 10")+'</g></svg>';},
  "cb5":function(){return B()+'<g id="cb5s0" opacity="0"><text x="200" y="14" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="800" fill="#5a4a30">1729 -- the Hardy-Ramanujan taxi-cab number</text>'+pill(26,38,150,'1^3 + 12^3','#d4870a')+pill(226,38,148,'9^3 + 10^3','#7a8c6e')+'</g>'+'<g id="cb5s1" opacity="0">'+pill(26,72,150,'1 + 1728 = 1729','#d4870a')+pill(226,72,148,'729 + 1000 = 1729','#7a8c6e')+'</g>'+'<g id="cb5s2" opacity="0"><text x="200" y="104" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#c8922a">Smallest number = sum of 2 cubes in 2 different ways</text><text x="200" y="126" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="800" fill="#5a4a30">Ramanujan spotted this instantly!</text></g>'+'<g id="cb5ans" opacity="0">'+svgAns("1^3+12^3 = 9^3+10^3 = 1729")+'</g></svg>';},
  "cb6":function(){return B()+'<g id="cb6s0" opacity="0"><text x="200" y="16" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">72 = 2^3 x 3^2 -- group in triples</text>'+triBox(18,28,'2','2','2',true)+'<rect x="128" y="28" width="28" height="22" rx="4" fill="#b85c2a"/><text x="142" y="43" text-anchor="middle" font-family="Share Tech Mono" font-size="11" font-weight="bold" fill="#fff">3</text><rect x="160" y="28" width="28" height="22" rx="4" fill="#b85c2a"/><text x="174" y="43" text-anchor="middle" font-family="Share Tech Mono" font-size="11" font-weight="bold" fill="#fff">3</text><text x="210" y="43" text-anchor="middle" font-family="Nunito" font-size="11" font-weight="800" fill="#b85c2a">need 1 more!</text>'+'</g>'+'<g id="cb6s1" opacity="0"><text x="200" y="74" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#7a8c6e">3 appears only twice -- needs 1 more</text><text x="200" y="96" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#c8922a">Multiply by 3</text></g>'+'<g id="cb6s2" opacity="0"><text x="200" y="122" text-anchor="middle" font-family="Nunito" font-size="14" font-weight="900" fill="#7a8c6e">72 x 3 = 216 = 6^3  OK</text></g>'+'<g id="cb6ans" opacity="0">'+svgAns("Multiply by 3")+'</g></svg>';},
  "cb7":function(){return B()+'<g id="cb7s0" opacity="0"><text x="200" y="16" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">192 = 2^6 x 3 -- group in triples</text>'+triBox(18,28,'2','2','2',true)+triBox(110,28,'2','2','2',true)+'<rect x="210" y="28" width="28" height="22" rx="4" fill="#b85c2a"/><text x="224" y="43" text-anchor="middle" font-family="Share Tech Mono" font-size="11" font-weight="bold" fill="#fff">3</text><text x="255" y="43" text-anchor="middle" font-family="Nunito" font-size="11" font-weight="800" fill="#b85c2a">lone!</text>'+'</g>'+'<g id="cb7s1" opacity="0"><text x="200" y="74" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#7a8c6e">3 has no complete triple -- must be removed</text><text x="200" y="96" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#c8922a">Divide by 3</text></g>'+'<g id="cb7s2" opacity="0"><text x="200" y="122" text-anchor="middle" font-family="Nunito" font-size="14" font-weight="900" fill="#7a8c6e">192 / 3 = 64 = 4^3  OK</text></g>'+'<g id="cb7ans" opacity="0">'+svgAns("Divide by 3")+'</g></svg>';},
  "cb8":function(){return B()+'<g id="cb8s0" opacity="0"><text x="200" y="16" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">cbrt(p/q) = cbrt(p) / cbrt(q) -- root each part</text><text x="200" y="44" text-anchor="middle" font-family="Share Tech Mono" font-size="20" font-weight="bold" fill="#5a4a30">cbrt(27/64)</text><line x1="160" y1="52" x2="116" y2="72" stroke="#5a4a30" stroke-width="2"/><line x1="240" y1="52" x2="280" y2="72" stroke="#5a4a30" stroke-width="2"/>'+pill(82,86,68,'cbrt(27)','#d4870a')+pill(248,86,68,'cbrt(64)','#7a8c6e')+'</g>'+'<g id="cb8s1" opacity="0">'+pill(82,114,68,'= 3','#d4870a')+pill(248,114,68,'= 4','#7a8c6e')+'</g>'+'<g id="cb8s2" opacity="0"><text x="200" y="142" text-anchor="middle" font-family="Share Tech Mono" font-size="18" font-weight="bold" fill="#c8922a">3/4</text></g>'+'<g id="cb8ans" opacity="0">'+svgAns("cbrt(27/64) = 3/4")+'</g></svg>';},
  "cb9":function(){return B()+'<g id="cb9s0" opacity="0"><text x="200" y="16" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">Convert decimal to fraction first</text>'+pill(110,40,180,'0.008 = 8/1000','#5a4a30')+'</g>'+'<g id="cb9s1" opacity="0"><line x1="200" y1="46" x2="140" y2="68" stroke="#5a4a30" stroke-width="2"/><line x1="200" y1="46" x2="260" y2="68" stroke="#5a4a30" stroke-width="2"/>'+pill(66,82,108,'cbrt(8) = 2','#d4870a')+pill(196,82,120,'cbrt(1000) = 10','#7a8c6e')+'</g>'+'<g id="cb9s2" opacity="0"><text x="200" y="114" text-anchor="middle" font-family="Share Tech Mono" font-size="18" font-weight="bold" fill="#c8922a">2/10 = 0.2</text><text x="200" y="138" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#7a8c6e">cbrt(0.008) = 0.2  OK</text></g>'+'<g id="cb9ans" opacity="0">'+svgAns("cbrt(0.008) = 0.2")+'</g></svg>';},
  "cb10":function(){var cubes=[1,8,27,64,125];var diffs=[7,19,37,61];var s=B()+'<g id="cb10s0" opacity="0"><text x="200" y="14" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="800" fill="#5a4a30">Consecutive cubes and their differences</text>';cubes.forEach(function(c,i){s+=pill(16+i*72,34,66,''+c,'#5a4a30');});s+='</g><g id="cb10s1" opacity="0">';diffs.forEach(function(d,i){s+='<line x1="'+(49+i*72)+'" y1="38" x2="'+(88+i*72)+'" y2="38" stroke="#c8922a" stroke-width="1.5" stroke-dasharray="4,2"/>';s+=pill(52+i*72,54,62,''+d,'#c8922a');});s+='<text x="200" y="76" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="800" fill="#5a4a30">7, 19, 37, 61 -- differences grow by 12, 18, 24...</text></g><g id="cb10s2" opacity="0"><text x="200" y="98" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#7a8c6e">(n+1)^3 - n^3 = 3n^2 + 3n + 1</text><text x="200" y="120" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="800" fill="#5a4a30">n=4: 3(16)+3(4)+1 = 61 OK</text></g><g id="cb10ans" opacity="0">'+svgAns("5^3-4^3 = 125-64 = 61")+'</g></svg>';return s;},
  "cb11":function(){return B()+'<g id="cb11s0" opacity="0"><text x="200" y="16" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">13824 -- group prime factors in triples</text>'+triBox(16,28,'2','2','2',true)+triBox(108,28,'2','2','2',true)+triBox(200,28,'3','3','3',true)+'</g>'+'<g id="cb11s1" opacity="0"><text x="200" y="74" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#7a8c6e">13824 = (2^2)^3 x (3^2)... regroup as 4^3 x 6^3</text><text x="200" y="96" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#c8922a">= (4x6)^3 = 24^3</text></g>'+'<g id="cb11s2" opacity="0"><text x="200" y="122" text-anchor="middle" font-family="Nunito" font-size="14" font-weight="900" fill="#7a8c6e">cbrt(13824) = 24  OK</text></g>'+'<g id="cb11ans" opacity="0">'+svgAns("cbrt(13824) = 24")+'</g></svg>';},
  "cb12":function(){var cx=220,cy=18,sz=58,d=24;var pts={A:[cx,cy+d],B:[cx+sz,cy],C:[cx+sz+d,cy+d],D:[cx+d,cy+2*d],E:[cx,cy+d+sz],F:[cx+sz,cy+sz],G:[cx+sz+d,cy+d+sz],H:[cx+d,cy+2*d+sz]};function ln(p1,p2,col,dash){return '<line x1="'+p1[0]+'" y1="'+p1[1]+'" x2="'+p2[0]+'" y2="'+p2[1]+'" stroke="'+(col||'#c8922a')+'" stroke-width="2"'+(dash?' stroke-dasharray="5,3"':'')+'/>';}return B()+'<g id="cb12s0" opacity="0"><text x="100" y="16" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="800" fill="#5a4a30">Volume = side^3</text>'+ln(pts.A,pts.B)+ln(pts.B,pts.C)+ln(pts.C,pts.D)+ln(pts.D,pts.A)+ln(pts.E,pts.F)+ln(pts.F,pts.G)+ln(pts.G,pts.H)+ln(pts.H,pts.E)+ln(pts.A,pts.E)+ln(pts.C,pts.G)+ln(pts.D,pts.H)+ln(pts.B,pts.F,'#ccc',true)+'<text x="'+(cx+sz/2+d/2)+'" y="'+(cy+d+sz/2+8)+'" text-anchor="middle" font-family="Share Tech Mono" font-size="11" fill="#d4870a">2744 cm3</text></g>'+'<g id="cb12s1" opacity="0"><text x="100" y="106" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="800" fill="#7a8c6e">side = cbrt(2744)</text></g>'+'<g id="cb12s2" opacity="0"><text x="100" y="130" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="900" fill="#c8922a">= 14 cm  OK</text></g>'+'<g id="cb12ans" opacity="0">'+svgAns("side = cbrt(2744) = 14 cm")+'</g></svg>';},
  "cb13":function(){var rows=[{n:'Even: 2',c:'2^3=8',col:'#7a8c6e',tag:'Even'},{n:'Even: 4',c:'4^3=64',col:'#7a8c6e',tag:'Even'},{n:'Odd: 3',c:'3^3=27',col:'#d4870a',tag:'Odd'},{n:'Odd: 5',c:'5^3=125',col:'#d4870a',tag:'Odd'}];var s=B()+'<g id="cb13s0" opacity="0"><text x="200" y="14" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="800" fill="#5a4a30">Does parity change when you cube a number?</text>';rows.forEach(function(r,i){s+='<rect x="20" y="'+(22+i*34)+'" width="160" height="26" rx="7" fill="'+r.col+'" opacity=".18"/><text x="100" y="'+(40+i*34)+'" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="800" fill="'+r.col+'">'+r.n+'</text><rect x="190" y="'+(22+i*34)+'" width="90" height="26" rx="7" fill="'+r.col+'" opacity=".25"/><text x="235" y="'+(40+i*34)+'" text-anchor="middle" font-family="Share Tech Mono" font-size="11" font-weight="bold" fill="'+r.col+'">'+r.c+'</text><rect x="290" y="'+(22+i*34)+'" width="80" height="26" rx="7" fill="'+r.col+'"/><text x="330" y="'+(40+i*34)+'" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="bold" fill="#fff">'+r.tag+'</text>';});s+='</g><g id="cb13s1" opacity="0"><text x="200" y="164" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#c8922a">Even^3 = Even  Odd^3 = Odd  -- always!</text></g><g id="cb13s2" opacity="0">'+svgAns("17^3 is Odd (17 is odd)")+'</g><g id="cb13ans" opacity="0">'+svgAns("17^3 is Odd")+'</g></svg>';return s;},
  "cb14":function(){return B()+'<g id="cb14s0" opacity="0"><text x="200" y="16" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">Find cbrt(-729) -- factorise 729 first</text>'+pill(130,40,140,'729 = 3^6 = (3^2)^3','#5a4a30')+'</g>'+'<g id="cb14s1" opacity="0">'+pill(140,72,120,'= 9^3','#d4870a')+'<text x="200" y="96" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#7a8c6e">So cbrt(729) = 9</text></g>'+'<g id="cb14s2" opacity="0"><text x="200" y="120" text-anchor="middle" font-family="Nunito" font-size="14" font-weight="900" fill="#c8922a">cbrt(-729) = -9</text><text x="200" y="144" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">Verify: (-9)^3 = -729  OK</text></g>'+'<g id="cb14ans" opacity="0">'+svgAns("cbrt(-729) = -9")+'</g></svg>';},
  "cb15":function(){return B()+'<g id="cb15s0" opacity="0"><text x="200" y="16" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#5a4a30">cbrt(x) = 4  means  x = 4^3 = 64</text>'+pill(140,42,120,'x = 64','#d4870a')+'</g>'+'<g id="cb15s1" opacity="0"><text x="200" y="78" text-anchor="middle" font-family="Nunito" font-size="13" font-weight="800" fill="#7a8c6e">cbrt(8x) = cbrt(8) x cbrt(x)</text>'+pill(50,100,118,'cbrt(8) = 2','#7a8c6e')+'<text x="182" y="104" text-anchor="middle" font-family="Nunito" font-size="14" font-weight="900" fill="#5a4a30">x</text>'+pill(198,100,118,'cbrt(x) = 4','#d4870a')+'</g>'+'<g id="cb15s2" opacity="0"><text x="200" y="132" text-anchor="middle" font-family="Nunito" font-size="14" font-weight="900" fill="#c8922a">cbrt(8x) = 2 x 4 = 8</text><text x="200" y="156" text-anchor="middle" font-family="Nunito" font-size="12" font-weight="800" fill="#5a4a30">Check: cbrt(8x64)=cbrt(512)=8 OK</text></g>'+'<g id="cb15ans" opacity="0">'+svgAns("cbrt(8x) = 8")+'</g></svg>';}
  };
  return m[t]?m[t]():'<svg viewBox="0 0 400 190"><text x="200" y="95" text-anchor="middle" font-family="Nunito" font-size="14" fill="#5a4a30">Loading...</text></svg>';
}"""

with open(PATH, 'r', encoding='utf-8') as f:
    content = f.read()

# Find and replace the getAnimSVG function
start = content.find('function getAnimSVG(t){')
if start == -1:
    print('ERROR: getAnimSVG not found')
    exit(1)

# Find closing brace of the function
# It ends with the return statement for unknown keys
end_marker = "return m[t]?m[t]()"
end = content.find(end_marker, start)
if end == -1:
    print('ERROR: end marker not found')
    exit(1)

# Find the closing of the function after the return
end = content.find('}\n', end) + 2

content = content[:start] + NEW_ANIM + '\n' + content[end:]

with open(PATH, 'w', encoding='utf-8') as f:
    f.write(content)

print(f'DONE: Replaced getAnimSVG in {PATH}')
